import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# Define the custom CUDA kernel for fused hinge loss computation
hinge_loss_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cassert>

__global__ void hinge_loss_kernel(const float* predictions, const float* targets, float* loss, int size) {
    __shared__ float shared_mem[256];

    // Robust global index computation: works for any grid/block dimension arrangement
    int block_id = blockIdx.x + blockIdx.y * gridDim.x + blockIdx.z * gridDim.x * gridDim.y;
    int idx = block_id * blockDim.x * blockDim.y * blockDim.z 
              + threadIdx.x 
              + threadIdx.y * blockDim.x 
              + threadIdx.z * blockDim.x * blockDim.y;

    int tid = threadIdx.x + threadIdx.y * blockDim.x + threadIdx.z * blockDim.x * blockDim.y;

    // Assert that kernel is launched with expected 1D block configuration
    // (optional but recommended for clarity)
    if (blockIdx.x == 0 && threadIdx.x == 0) {
        assert(blockDim.y == 1 && blockDim.z == 1 && "Expected 1D block configuration");
    }

    float thread_loss = 0.0f;

    if (idx < size) {
        float margin = 1.0f - predictions[idx] * targets[idx];
        thread_loss = margin > 0.0f ? margin : 0.0f;
    }

    // Only threads within the original blockDim.x boundary participate in reduction
    if (tid < 256) {
        shared_mem[tid] = thread_loss;
    }
    __syncthreads();

    // Parallel reduction for sum within block (assuming power of 2)
    for (int stride = 256 / 2; stride > 0; stride >>= 1) {
        if (tid < stride && (tid + stride) < 256) {
            shared_mem[tid] += shared_mem[tid + stride];
        }
        __syncthreads();
    }

    // First thread writes block sum to global memory
    if (tid == 0) {
        loss[block_id] = shared_mem[0];
    }
}

torch::Tensor hinge_loss_cuda(torch::Tensor predictions, torch::Tensor targets) {
    auto size = predictions.numel();

    // Use explicit 1D launch configuration
    const int block_size = 256;
    const int num_blocks = (size + block_size - 1) / block_size;

    // Explicitly create 1D grid
    dim3 grid(num_blocks, 1, 1);
    dim3 block(block_size, 1, 1);

    // Allocate device memory for block sums
    auto block_sums = torch::zeros({num_blocks}, torch::TensorOptions().dtype(torch::kFloat32).device(predictions.device()));

    // Launch kernel with explicit 1D configuration
    hinge_loss_kernel<<<grid, block>>>(
        predictions.data_ptr<float>(),
        targets.data_ptr<float>(),
        block_sums.data_ptr<float>(),
        size
    );

    // Final reduction on CPU (small number of elements)
    auto final_loss = block_sums.sum() / size;

    return final_loss;
}
"""

